figma.showUI(__html__,{themeColors:!0,width:240,height:288});function m(r){const t=new Map;for(const s of r.children)if(s.type==="COMPONENT"){const n=s.name.split(",").map(e=>e.trim());for(const e of n){const[o,i]=e.split("=").map(a=>a.trim());o&&i&&(t.has(o)||t.set(o,new Set),t.get(o).add(i))}}return t}function f(){const r=figma.currentPage.selection;if(console.log("Current selection:",r),r.length===0){console.log("No selection made."),figma.ui.postMessage({type:"ERROR",message:"Please select one or more component sets."});return}const t=r.filter(e=>e.type==="COMPONENT_SET");if(t.length!==r.length){console.log("Selection contains non-component set layers."),figma.ui.postMessage({type:"ERROR",message:"All selected layers must be component sets."});return}let s=m(t[0]);for(let e=1;e<t.length;e++){const o=m(t[e]),i=new Map;for(const[a,l]of s.entries())if(o.has(a)){const p=o.get(a),c=new Set([...l].filter(u=>p.has(u)));c.size>0&&i.set(a,c)}s=i}if(s.size===0){console.log("No common properties with shared values found."),figma.ui.postMessage({type:"ERROR",message:"No shared properties with common values found across the selection."});return}const n={};for(const[e,o]of s.entries())n[e]=Array.from(o);figma.ui.postMessage({type:"INIT_PROPERTIES",data:n})}figma.on("selectionchange",f);figma.ui.onmessage=r=>{if(r.type==="RENAME_VALUE"){const{property:t,oldValue:s,newValue:n}=r;if(!n||n.trim()===""){figma.notify("New value cannot be empty.",{error:!0});return}if(n.includes("=")||n.includes(",")){figma.notify('New value cannot contain "=" or "," characters.',{error:!0});return}const e=figma.currentPage.selection.filter(i=>i.type==="COMPONENT_SET");let o=0;for(const i of e)for(const a of i.children){if(a.type!=="COMPONENT")continue;const l=a.name.split(",").map(c=>c.trim()),p=l.findIndex(c=>c.trim()===`${t}=${s}`);p!==-1&&(l[p]=`${t}=${n}`,a.name=l.join(", "),o++)}figma.notify(`✅ Renamed ${o} total variants from "${s}" to "${n}".`),figma.closePlugin()}};f();
